import jwt from "jsonwebtoken";

// Signing/verifying session tokens for the bookmarks API.
//
// NOTE (fixture): this module is written against jsonwebtoken 8.x semantics.
// The tests in test/auth.test.js exercise the 8.x behaviour on purpose.
const SECRET = process.env.JWT_SECRET || "dev-only-fixture-secret";

// In 8.x, sign() accepts a payload that already carries its own `exp` claim
// as long as we do NOT also pass options.expiresIn. We build the expiry into
// the payload ourselves so callers can hand us fully-formed claim sets.
export function issueToken(claims, ttlSeconds = 3600) {
  const now = Math.floor(Date.now() / 1000);
  const payload = { ...claims, iat: now, exp: now + ttlSeconds };
  return jwt.sign(payload, SECRET, { algorithm: "HS256" });
}

export function verifyToken(token) {
  return jwt.verify(token, SECRET);
}

// 8.x returns the decoded payload (or null); we surface the raw header too.
export function inspect(token) {
  return jwt.decode(token, { complete: true });
}

import request from "request";
import { parseStringPromise } from "xml2js";

// Import bookmarks from a remote XML feed. Legacy code path: it still uses the
// (deprecated) `request` library because it was written years ago and never
// migrated. `request` is the only thing pulling tough-cookie into the graph.
export function fetchXml(url) {
  return new Promise((resolve, reject) => {
    request({ url, method: "GET", jar: true }, (err, res, body) => {
      if (err) return reject(err);
      if (res.statusCode >= 400) {
        return reject(new Error(`upstream ${res.statusCode}`));
      }
      resolve(body);
    });
  });
}

export async function importBookmarks(xmlString) {
  const doc = await parseStringPromise(xmlString, { explicitArray: false });
  const items = doc?.bookmarks?.bookmark;
  if (!items) return [];
  const list = Array.isArray(items) ? items : [items];
  return list.map((b) => ({ title: b.title, url: b.url }));
}

import { test } from "node:test";
import assert from "node:assert/strict";
import { createApp } from "../src/app.js";
import { issueToken, verifyToken, inspect } from "../src/auth.js";
import { listen } from "./helpers.js";

test("issues a token whose payload round-trips through verify", () => {
  const token = issueToken({ sub: "alice", role: "member" }, 3600);
  const claims = verifyToken(token);
  assert.equal(claims.sub, "alice");
  assert.equal(claims.role, "member");
  assert.equal(typeof claims.exp, "number");
  assert.equal(claims.exp - claims.iat, 3600);
});

test("signs with HS256 and exposes the header via decode(complete)", () => {
  const decoded = inspect(issueToken({ sub: "bob" }));
  assert.equal(decoded.header.alg, "HS256");
  assert.equal(decoded.header.typ, "JWT");
});

test("login then /me returns the authenticated user", async () => {
  const { base, close } = await listen(createApp());
  try {
    const login = await fetch(`${base}/login`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ user: "carol" }),
    });
    assert.equal(login.status, 200);
    const { token } = await login.json();
    const me = await fetch(`${base}/me`, {
      headers: { authorization: `Bearer ${token}` },
    });
    assert.equal(me.status, 200);
    assert.equal((await me.json()).user, "carol");
  } finally {
    close();
  }
});

test("rejects a garbage token", async () => {
  const { base, close } = await listen(createApp());
  try {
    const me = await fetch(`${base}/me`, {
      headers: { authorization: "Bearer not.a.jwt" },
    });
    assert.equal(me.status, 401);
  } finally {
    close();
  }
});

import { test, before, after } from "node:test";
import assert from "node:assert/strict";
import http from "node:http";
import { fetchXml, importBookmarks } from "../src/importer.js";
import { createApp } from "../src/app.js";
import { listen } from "./helpers.js";

const SAMPLE = `<?xml version="1.0"?>
<bookmarks>
  <bookmark><title>Docs</title><url>https://docs.example.com</url></bookmark>
  <bookmark><title>Status</title><url>https://status.example.com</url></bookmark>
</bookmarks>`;

let origin;
let originBase;

before(async () => {
  origin = http.createServer((req, res) => {
    if (req.url === "/feed.xml") {
      res.setHeader("content-type", "application/xml");
      res.end(SAMPLE);
    } else {
      res.writeHead(404);
      res.end();
    }
  });
  await new Promise((r) => origin.listen(0, r));
  originBase = `http://127.0.0.1:${origin.address().port}`;
});

after(() => origin.close());

test("fetches a remote XML feed via request", async () => {
  const body = await fetchXml(`${originBase}/feed.xml`);
  assert.match(body, /<bookmarks>/);
});

test("parses bookmarks out of the XML", async () => {
  const items = await importBookmarks(SAMPLE);
  assert.equal(items.length, 2);
  assert.deepEqual(items[0], { title: "Docs", url: "https://docs.example.com" });
});

test("POST /import ingests an XML body", async () => {
  const { base, close } = await listen(createApp());
  try {
    const res = await fetch(`${base}/import`, {
      method: "POST",
      headers: { "content-type": "application/xml" },
      body: SAMPLE,
    });
    assert.equal(res.status, 200);
    assert.equal((await res.json()).imported, 2);
  } finally {
    close();
  }
});

